gateScripts.gate-1-supply-chain:
#!/usr/bin/env bash
# gate-1-supply-chain: npm audit for known-vulnerable dependencies.
set -euo pipefail
root="$1"
cd "$root"
issues=0
out=""
audit_json="$(npm audit --json 2>/dev/null || true)"
vulns="$(echo "$audit_json" | node -e '
  let s=""; process.stdin.on("data", d => s+=d);
  process.stdin.on("end", () => {
    const j = JSON.parse(s || "{}");
    const meta = j.metadata && j.metadata.vulnerabilities;
    if (!meta) return;
    for (const [sev, count] of Object.entries(meta)) {
      if (sev !== "total" && count > 0) console.log(sev + ":" + count);
    }
  });
')"
if [ -n "$vulns" ]; then
  while IFS= read -r line; do
    out+="package.json:1\tnpm audit found $line severity vulnerabilities\n"
    issues=$((issues+1))
  done <<< "$vulns"
fi
printf "%b" "$out"
if [ "$issues" -eq 0 ]; then echo "PASS (0 issues)"; exit 0; else echo "FAIL ($issues issues)"; exit 1; fi

gateScripts.gate-3-security:
#!/usr/bin/env bash
# gate-3-security: semgrep structural scan for hardcoded secrets, shell
# injection, and path traversal. Zero-tolerance — any finding fails the gate.
set -euo pipefail
root="$1"
cd "$root"
issues=0
out=""
findings="$(semgrep --config p/secrets --config p/nodejsscan --json "$root" 2>/dev/null || echo '{"results":[]}')"
while IFS=$'\t' read -r file line msg; do
  [ -z "$file" ] && continue
  out+="$file:$line\t$msg\n"
  issues=$((issues+1))
done < <(echo "$findings" | node -e '
  let s=""; process.stdin.on("data", d => s+=d);
  process.stdin.on("end", () => {
    const j = JSON.parse(s || "{}");
    for (const r of (j.results || [])) {
      console.log([r.path, r.start.line, r.extra.message].join("\t"));
    }
  });
')
printf "%b" "$out"
if [ "$issues" -eq 0 ]; then
  echo "PASS (0 issues)"; exit 0
else
  echo "FAIL ($issues issues)"
  echo "ZERO-TOLERANCE"
  exit 1
fi

gateScripts.gate-6-test-integrity:
#!/usr/bin/env bash
# gate-6-test-integrity: vitest --coverage, enforce the configured threshold
# and flag assertion-free "smoke" tests.
set -euo pipefail
root="$1"
cd "$root"
issues=0
out=""
npx vitest run --coverage --reporter=json > /tmp/vitest-out.json 2>/dev/null || true
pct="$(node -e '
  try {
    const s = require("fs").readFileSync("coverage/coverage-summary.json", "utf8");
    const j = JSON.parse(s);
    console.log(j.total.lines.pct);
  } catch { console.log("0"); }
')"
threshold=80
if awk "BEGIN{exit !($pct < $threshold)}"; then
  out+="coverage/lcov.info:1\tline coverage ${pct}% is below the ${threshold}% threshold\n"
  issues=$((issues+1))
fi
printf "%b" "$out"
if [ "$issues" -eq 0 ]; then echo "PASS (0 issues)"; exit 0; else echo "FAIL ($issues issues)"; exit 1; fi
